contract TimeLockedVault {
    owner: Address;
    unlock_block: u64;

    pub fn spend(self, ctx: SpendContext) -> bool {
        ctx.block_height >= self.unlock_block
        && ctx.signer == self.owner
    }
}

// A covenant that enforces a specific output address
contract FixedDestination {
    destination: Address;

    pub fn spend(self, ctx: SpendContext) -> bool {
        ctx.outputs.len() == 1
        && ctx.outputs[0].address == self.destination
    }
}
